const payload = $input.first().json || {};
const eventType = String(payload.event_type || payload.status || '').trim();
const workflowStatus = String(payload.workflow_status || payload.status || '').trim();
const conversionId = String(payload.conversion_id || payload.pdf_hash || payload.cid || '').trim();

return [
  {
    json: {
      received: true,
      event_type: eventType,
      workflow_status: workflowStatus,
      conversion_id: conversionId,
      payload
    }
  }
];
